mapper.select:
select a.id as attendanceId, e.id as eventId, e.title, e.activity_start_at, e.attendees, e.budget, e.event_status, e.event_type, e.location, b.id as hostedBrandId, b.brand_name as hostedBrandName, b.avator as hostedBrandAvatar, b.customer_id as hostedBrandUserId from app_meetr_attendee a inner join app_meetr_event e on a.event_id = e.id inner join brand b on e.hosted_brand_id = b.id
a.member_brand_id = #{currentBrandId}
AND (locate(#{dto.q}, e.title) > 0 or locate(#{dto.q}, b.brand_name) > 0)
AND e.event_status = #{dto.eventStatus}
order by a.create_at desc
